define("mod_redaction/grading",["jquery"],function($){var grading={cmid:0,submissionid:0,pollInterval:null,init:function(config){this.cmid=config.cmid;this.submissionid=config.submissionid||0;this.checkPendingEvaluation()},checkPendingEvaluation:function(){var self=this;var pendingIndicator=$(".ai-pending");if(pendingIndicator.length>0){this.pollInterval=setInterval(function(){self.pollEvaluationStatus()},5000)}},pollEvaluationStatus:function(){var self=this;$.ajax({url:M.cfg.wwwroot+"/mod/redaction/ajax/get_evaluation_status.php",method:"GET",data:{id:this.cmid,submissionid:this.submissionid,sesskey:M.cfg.sesskey},dataType:"json",success:function(response){if(response.success&&response.status){if(response.status==="completed"||response.status==="failed"||response.status==="applied"){clearInterval(self.pollInterval);location.reload()}}},error:function(){}})},stopPolling:function(){if(this.pollInterval){clearInterval(this.pollInterval);this.pollInterval=null}}};return grading});
